/**
 * MAPEAMENTO DE DADOS: Planilha -> Tabela liberation_data
 * FILTRO: Apenas admissões a partir de 01/01/2026
 */

function excelSerialToDate(serial) {
  const excelEpoch = new Date(Date.UTC(1899, 11, 30));
  return new Date(excelEpoch.getTime() + Number(serial) * 86400000);
}

function parseDate(value) {
  if (!value || value === "") return null;
  if (value instanceof Date && !isNaN(value)) return value;
  if (typeof value === 'number') return excelSerialToDate(value);
  const str = String(value).trim();
  const dmy = str.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (dmy) {
    const [, d, m, y] = dmy;
    return new Date(Date.UTC(+y, +m - 1, +d));
  }
  const iso = new Date(str);
  return isNaN(iso) ? null : iso;
}

function formatISO(date) {
  return date ? date.toISOString().split('T')[0] : null;
}

function normalizeKey(key) {
  return key?.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]/g, '') || '';
}

function getField(row, ...variants) {
  const keys = Object.keys(row);
  for (const v of variants) {
    const target = normalizeKey(v);
    for (const k of keys) {
      if (normalizeKey(k) === target) return row[k];
    }
  }
  return null;
}

const items = $input.all();
const output = [];
const DATA_CORTE = new Date(Date.UTC(2026, 0, 1));

for (const item of items) {
  const row = item.json || {};

  const chapa = String(getField(row, 'MAT', 'MATRICULA', 'CHAPA', 'chapa') || '').trim();
  const nome = String(getField(row, 'NOME', 'NOME COMPLETO', 'nome') || '').trim();

  if (!chapa || !nome || nome.toLowerCase().includes('mat')) continue;

  const rawAdmissao = getField(row, 'DATA ADMISSÃO', 'ADMISSAO', 'DATA ADMISSAO', 'DATA ADMISSION');
  const objDateAdmissao = parseDate(rawAdmissao);

  if (!objDateAdmissao || objDateAdmissao < DATA_CORTE) {
     continue;
  }

  const rowData = {
    chapa,
    nome,
    funcao: getField(row, 'FUNÇÃO RM ATUALIZADA', 'FUNCAO', 'CARGO'),
    area: getField(row, 'AREA DE NEGOCIO', 'AREA'),
    status: getField(row, 'STATUS', 'SITUACAO'),
    cid: getField(row, 'CIP DE LIBERAÇÃO', 'CIP'),
    rh: getField(row, 'RH'),
    saude: getField(row, 'SAÚDE', 'SAUDE'),
    seguranca: getField(row, 'SEGURANÇA', 'SEGURANCA'),
    grd: getField(row, 'GRD', 'GERÊNCIA', 'GERENCIA'),
    obs_grd: getField(row, 'OBSERVAÇÃO GRD', 'OBSERVACAO GRD', 'OBS'),
    data_admissao: formatISO(objDateAdmissao),
    liberacao_ecoordin: formatISO(parseDate(getField(row, 'DATA DE LIBERAÇÃO E-COORDINA'))),
    envio_cliente: formatISO(parseDate(getField(row, 'ENVIO PARA O CLIENTE', 'ENVIO CLIENTE')))
  };

  output.push({ json: rowData });
}

return output;

// --- OTIMIZAÇÃO DE PERFORMANCE (REFERÊNCIA CORRIGIDA) ---

// 1. Carrega os dados transformados (Nome do nó corrigido aqui)
const planilhaItems = $("Transformar_Dados").all();

// 2. Carrega os dados do Supabase
const supabaseItems = $input.all();

const bancoMap = {};
for (const item of supabaseItems) {
    if (item.json && item.json.chapa) {
        bancoMap[String(item.json.chapa)] = item.json;
    }
}

const results = [];

for (const pItem of planilhaItems) {
    const planilhaData = pItem.json;
    if (!planilhaData || !planilhaData.chapa) continue;

    const chapa = String(planilhaData.chapa);
    const dadosBanco = bancoMap[chapa];
    const existeNoBanco = !!dadosBanco;

    if (!existeNoBanco) {
        results.push({
            json: {
                ...planilhaData,
                operation: 'INSERT'
            }
        });
        continue;
    }

    const updateFields = {};
    let hasChanges = false;
    const comparisonFields = ['nome', 'funcao', 'status', 'area', 'cid', 'rh', 'saude', 'seguranca', 'grd', 'obs_grd', 'data_admissao', 'liberacao_ecoordin', 'envio_cliente'];

    for (const key of comparisonFields) {
        const vP = (planilhaData[key] === null || planilhaData[key] === undefined) ? '' : String(planilhaData[key]).trim();
        const vB = (dadosBanco[key] === null || dadosBanco[key] === undefined) ? '' : String(dadosBanco[key]).trim();

        if (vP !== vB) {
            updateFields[key] = planilhaData[key];
            hasChanges = true;
        }
    }

    if (hasChanges) {
        results.push({
            json: {
                chapa: chapa,
                operation: 'UPDATE',
                data: updateFields
            }
        });
    } else {
        results.push({
            json: {
                chapa: chapa,
                operation: 'SKIP',
                message: 'Dados idênticos'
            }
        });
    }
}

return results;
